import { useState, useEffect } from 'react';
import axios from 'axios';
import './ShopHome.css';

const API = 'http://localhost:5000/api';

function Stars({ rating }) {
  return (
    <div className="stars">
      {[1,2,3,4,5].map(s => (
        <span key={s} className={`star ${s <= rating ? '' : 'empty'}`}>★</span>
      ))}
    </div>
  );
}

export default function ShopHome() {
  const [tab, setTab] = useState('home');
  const [settings, setSettings] = useState({});
  const [products, setProducts] = useState([]);
  const [reviews, setReviews] = useState([]);
  const [reviewForm, setReviewForm] = useState({ customer_name: '', rating: 5, comment: '' });
  const [reviewMsg, setReviewMsg] = useState('');
  const [hoverRating, setHoverRating] = useState(0);

  useEffect(() => {
    axios.get(`${API}/settings`).then(r => setSettings(r.data)).catch(() => {});
    axios.get(`${API}/products`).then(r => setProducts(r.data)).catch(() => {});
    axios.get(`${API}/reviews`).then(r => setReviews(r.data)).catch(() => {});
  }, []);

  const avgRating = reviews.length
    ? (reviews.reduce((a, r) => a + r.rating, 0) / reviews.length).toFixed(1)
    : '0';

  const submitReview = async () => {
    if (!reviewForm.customer_name.trim()) { setReviewMsg('❌ பேரு சொல்லுங்க'); return; }
    await axios.post(`${API}/reviews`, reviewForm);
    setReviewMsg('✅ நன்றி! Admin approve பண்ணிய பிறகு show ஆகும்');
    setReviewForm({ customer_name: '', rating: 5, comment: '' });
  };

  const hours = [
    { day: 'திங்கள்', time: '7:30 am – 9:30 pm' },
    { day: 'செவ்வாய்', time: '7:30 am – 9:30 pm' },
    { day: 'புதன்', time: '7:30 am – 9:30 pm' },
    { day: 'வியாழன்', time: '7:30 am – 9:30 pm' },
    { day: 'வெள்ளி', time: '7:30 am – 9:30 pm' },
    { day: 'சனி', time: '7:30 am – 7:30 pm' },
    { day: 'ஞாயிறு', time: '7:30 – 9:30 am' },
  ];

  return (
    <div className="shop-page">
      {/* HEADER */}
      <header className="shop-header">
        <div className="shop-header-inner">
          <div className="shop-logo">
            <span className="shop-icon">👗</span>
            <div>
              <h1>{settings.shop_name || 'அகத்தியர் Store'}</h1>
              <p>Dress Store · Est. 2024</p>
            </div>
          </div>
          <nav className="shop-nav">
            {[
              { id: 'home', label: 'Home' },
              { id: 'products', label: 'Products' },
              { id: 'reviews', label: 'Reviews' },
              { id: 'about', label: 'About' },
            ].map(t => (
              <button key={t.id}
                className={`nav-btn ${tab === t.id ? 'active' : ''}`}
                onClick={() => setTab(t.id)}>
                {t.label}
              </button>
            ))}
          </nav>
        </div>
      </header>

      <main className="shop-main">

        {/* ── HOME ── */}
        {tab === 'home' && (
          <>
            <section className="hero-section">
              <div className="hero-bg" />
              <div className="hero-glow" />
              <div className="hero-content">
                <span className="hero-tag">✦ Welcome to our Store ✦</span>
                <h2>சிறந்த <em>Dress</em><br />சிறந்த விலையில்</h2>
                <p>உயர்தரமான ஆடைகள் உங்களுக்காக காத்திருக்கின்றன</p>
                <div className="hero-rating">
                  <Stars rating={Math.round(parseFloat(avgRating))} />
                  <span>{avgRating} out of 5 · {reviews.length} reviews</span>
                </div>
                <div className="hero-btns">
                  <button className="btn-gold-fill" onClick={() => setTab('products')}>
                    👗 Products பாருங்க
                  </button>
                  <button className="btn-outline-gold" onClick={() => setTab('reviews')}>
                    ⭐ Reviews
                  </button>
                </div>
              </div>
              <div className="hero-scroll">
                <span>Scroll</span>
                <div className="scroll-line" />
              </div>
            </section>

            <section className="info-section">
              <div className="info-section-inner">
                <p className="section-label">✦ Find Us ✦</p>
                <div className="info-cards">
                  <div className="info-card">
                    <span className="info-icon">📍</span>
                    <h3>Address</h3>
                    <p>{settings.shop_address || 'C.Ayyampalayam, Manachnallur, Tamil Nadu 621005'}</p>
                  </div>
                  <div className="info-card">
                    <span className="info-icon">📞</span>
                    <h3>Phone</h3>
                    <p><a href={`tel:${settings.shop_phone}`}>{settings.shop_phone || '074483 67291'}</a></p>
                  </div>
                  <div className="info-card">
                    <span className="info-icon">🕐</span>
                    <h3>Today's Hours</h3>
                    <p><span className="open-badge">● Open Now</span></p>
                  </div>
                </div>
              </div>
            </section>
          </>
        )}

        {/* ── PRODUCTS ── */}
        {tab === 'products' && (
          <section className="products-section">
            <div className="section-header">
              <h2 className="section-title">Our <span>Collection</span></h2>
              <p className="section-subtitle">✦ Handpicked Dresses ✦</p>
            </div>
            {products.length === 0 ? (
              <div className="empty-state">
                <div style={{fontSize:'3rem', marginBottom:'16px'}}>👗</div>
                <p>Products விரைவில் வரும்...</p>
              </div>
            ) : (
              <div className="products-grid">
                {products.map(p => (
                  <div key={p.id} className="product-card">
                    <div className="product-icon">👗</div>
                    <h3>{p.name}</h3>
                    {p.category && <div><span className="product-category">{p.category}</span></div>}
                    <div className="product-price">₹{p.price.toLocaleString()}</div>
                    <div className={`${p.stock > 5 ? 'in-stock' : p.stock > 0 ? 'low-stock' : 'out-stock'}`}>
                      {p.stock > 5 ? '● Available' : p.stock > 0 ? `⚠ Only ${p.stock} left` : '✕ Out of Stock'}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </section>
        )}

        {/* ── REVIEWS ── */}
        {tab === 'reviews' && (
          <section className="reviews-section">
            <div className="reviews-inner">
              <div className="section-header" style={{textAlign:'center'}}>
                <h2 className="section-title">Customer <span>Reviews</span></h2>
                <p className="section-subtitle">✦ What our customers say ✦</p>
              </div>

              <div className="rating-summary">
                <div className="big-rating">{avgRating}</div>
                <Stars rating={Math.round(parseFloat(avgRating))} />
                <p>{reviews.length} verified reviews</p>
              </div>

              {reviews.length > 0 && (
                <div className="reviews-grid">
                  {reviews.map(r => (
                    <div key={r.id} className="review-card">
                      <div className="review-header">
                        <div className="reviewer-avatar">{r.customer_name[0].toUpperCase()}</div>
                        <div>
                          <div className="review-name">{r.customer_name}</div>
                          <Stars rating={r.rating} />
                        </div>
                        <span className="review-date">{r.created_at}</span>
                      </div>
                      {r.comment && <p className="review-comment">"{r.comment}"</p>}
                    </div>
                  ))}
                </div>
              )}

              <div className="review-form-card">
                <h3>✍️ Review எழுதுங்க</h3>
                {reviewMsg && <div className="alert alert-success" style={{marginBottom:'16px'}}>{reviewMsg}</div>}
                <div className="form-group">
                  <label>உங்கள் பேரு</label>
                  <input className="form-control" placeholder="Name..." value={reviewForm.customer_name}
                    onChange={e => setReviewForm({...reviewForm, customer_name: e.target.value})} />
                </div>
                <div className="form-group">
                  <label>Rating</label>
                  <div className="star-picker">
                    {[1,2,3,4,5].map(s => (
                      <span key={s}
                        className={`star-btn ${(hoverRating || reviewForm.rating) >= s ? 'active' : ''}`}
                        onMouseEnter={() => setHoverRating(s)}
                        onMouseLeave={() => setHoverRating(0)}
                        onClick={() => setReviewForm({...reviewForm, rating: s})}>★</span>
                    ))}
                  </div>
                </div>
                <div className="form-group">
                  <label>Comment (Optional)</label>
                  <textarea className="form-control" rows={3} placeholder="உங்கள் experience பகிருங்க..."
                    value={reviewForm.comment}
                    onChange={e => setReviewForm({...reviewForm, comment: e.target.value})} />
                </div>
                <button className="btn-gold-fill" style={{width:'100%', borderRadius:'10px'}} onClick={submitReview}>
                  Submit Review
                </button>
              </div>
            </div>
          </section>
        )}

        {/* ── ABOUT ── */}
        {tab === 'about' && (
          <section className="about-section">
            <div className="section-header">
              <h2 className="section-title">About <span>Us</span></h2>
              <p className="section-subtitle">✦ Our Story ✦</p>
            </div>
            <div className="about-card">
              <h3>🏪 {settings.shop_name || 'அகத்தியர் Store'}</h3>
              <p>சிறந்த தரமான dress-கள் கிடைக்கும் எங்கள் shop-ல். உங்கள் விசேஷ தருணங்களை இன்னும் அழகாக்குவோம்.</p>
              <div className="hours-table">
                <h4>Working Hours</h4>
                {hours.map(h => (
                  <div key={h.day} className="hours-row">
                    <span>{h.day}</span><span>{h.time}</span>
                  </div>
                ))}
              </div>
              <div className="contact-section">
                <h4>Contact</h4>
                <p>📞 {settings.shop_phone || '074483 67291'}</p>
                <p>📍 {settings.shop_address || 'C.Ayyampalayam, Manachnallur, Tamil Nadu 621005'}</p>
              </div>
            </div>
          </section>
        )}
      </main>

      <footer className="shop-footer">
        <p>© 2024 {settings.shop_name || 'அகத்தியர் Store'} · All Rights Reserved</p>
        <a href="/admin/login" className="admin-link">Admin</a>
      </footer>
    </div>
  );
}
